package cn.nobeta.dingdong.pay.security;import cn.nobeta.dingdong.common.exception.BusinessException;public final class PayUserContext{private static final ThreadLocal<CurrentPayUser> H=new ThreadLocal<>();private PayUserContext(){}public static void set(CurrentPayUser u){H.set(u);}public static CurrentPayUser require(){var u=H.get();if(u==null)throw new BusinessException("AUTH_UNAUTHORIZED","请先登录");return u;}public static void clear(){H.remove();}}
